def greedy_assignment(cost_matrix):
    n_agents, n_tasks = cost_matrix.shape
    row_ind, col_ind = [], []
    assigned_tasks, assigned_agents = set(), set()
    pairs = sorted(
        [(cost_matrix[i, j], i, j) for i in range(n_agents) for j in range(n_tasks)]
    )
    for cost, i, j in pairs:
        if i not in assigned_agents and j not in assigned_tasks:
            row_ind.append(i)
            col_ind.append(j)
            assigned_agents.add(i)
            assigned_tasks.add(j)
            if len(assigned_agents) == min(n_agents, n_tasks):
                break
    return np.array(row_ind), np.array(col_ind)


class WarehouseSimulator:
    def __init__(
        self,
        grid_size=20,
        n_agents=20,
        n_tasks=30,
        obstacles=None,
        hotspots=None,
        decay_rate=0.95,
    ):
        self.grid_size, self.n_agents, self.n_tasks = grid_size, n_agents, n_tasks
        self.obstacles = obstacles if obstacles else set()
        self.hotspots = hotspots if hotspots else []
        self.decay_rate = decay_rate
        self.conflict_memory = np.zeros((grid_size, grid_size))
        self.reset()

    def _valid_position(self, pos):
        return (
            0 <= pos[0] < self.grid_size
            and 0 <= pos[1] < self.grid_size
            and tuple(pos) not in self.obstacles
        )

    def _random_valid_position(self):
        for _ in range(100):
            pos = np.random.randint(0, self.grid_size, 2)
            if self._valid_position(pos):
                return pos
        return np.array([0, 0])

    def _hotspot_biased_position(self):
        if self.hotspots and np.random.random() < 0.6:
            hotspot = self.hotspots[np.random.randint(len(self.hotspots))]
            pos = np.clip(hotspot + np.random.randint(-2, 3, 2), 0, self.grid_size - 1)
            if self._valid_position(pos):
                return pos
        return self._random_valid_position()

    def reset(self, keep_memory=False):
        self.agent_positions = np.array(
            [self._random_valid_position() for _ in range(self.n_agents)]
        )
        self.task_positions = np.array(
            [self._hotspot_biased_position() for _ in range(self.n_tasks)]
        )
        self.task_active = np.ones(self.n_tasks, dtype=bool)
        self.agent_targets = [-1] * self.n_agents
        self.time_step, self.tasks_completed, self.congestion_events = 0, 0, 0
        if not keep_memory:
            self.conflict_memory = np.zeros((self.grid_size, self.grid_size))
        return self.get_state()

    def get_state(self):
        agent_grid = np.zeros((self.grid_size, self.grid_size))
        task_grid = np.zeros((self.grid_size, self.grid_size))
        for pos in self.agent_positions:
            agent_grid[pos[0], pos[1]] += 1
        for i, pos in enumerate(self.task_positions):
            if self.task_active[i]:
                task_grid[pos[0], pos[1]] += 1
        memory_norm = self.conflict_memory / (self.conflict_memory.max() + 1e-6)
        return np.stack([agent_grid, task_grid, memory_norm], axis=0)

    def _get_path_astar(self, start, end):
        from heapq import heappush, heappop

        start, end = tuple(start), tuple(end)
        if start == end:
            return [start]
        open_set = [(0, start)]
        came_from, g_score = {}, {start: 0}
        while open_set:
            _, current = heappop(open_set)
            if current == end:
                path = [current]
                while current in came_from:
                    current = came_from[current]
                    path.append(current)
                return path[::-1]
            for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                neighbor = (current[0] + dx, current[1] + dy)
                if not self._valid_position(np.array(neighbor)):
                    continue
                tentative_g = g_score[current] + 1
                if tentative_g < g_score.get(neighbor, float("inf")):
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g
                    f = (
                        tentative_g
                        + abs(neighbor[0] - end[0])
                        + abs(neighbor[1] - end[1])
                    )
                    heappush(open_set, (f, neighbor))
        return [start]

    def update_conflict_memory(self):
        self.conflict_memory *= self.decay_rate
        agent_grid = np.zeros((self.grid_size, self.grid_size))
        for pos in self.agent_positions:
            agent_grid[pos[0], pos[1]] += 1
        conflict_cells = agent_grid > 1
        self.conflict_memory += conflict_cells * agent_grid
        self.congestion_events += np.sum(agent_grid > 2)

    def assign_tasks(self, assignment):
        for agent_idx, task_idx in assignment:
            if task_idx >= 0 and self.task_active[task_idx]:
                self.agent_targets[agent_idx] = task_idx

    def step(self):
        self.time_step += 1
        self.update_conflict_memory()
        for i in range(self.n_agents):
            target_idx = self.agent_targets[i]
            if target_idx >= 0 and self.task_active[target_idx]:
                target_pos = self.task_positions[target_idx]
                if np.sum(np.abs(target_pos - self.agent_positions[i])) <= 1:
                    self.task_active[target_idx] = False
                    self.tasks_completed += 1
                    self.agent_targets[i] = -1
                else:
                    path = self._get_path_astar(self.agent_positions[i], target_pos)
                    if len(path) > 1:
                        self.agent_positions[i] = np.array(path[1])
        for idx in np.where(~self.task_active)[0]:
            if np.random.random() < 0.3:
                self.task_positions[idx] = self._hotspot_biased_position()
                self.task_active[idx] = True
        return self.get_state()


def create_sparse_warehouse(gs=20):
    obs = {(i, j) for i in range(5, 15, 5) for j in range(3, gs - 3, 4)}
    return obs, [np.array([5, 5]), np.array([15, 15])], "sparse_warehouse"


def create_bottleneck_warehouse(gs=20):
    obs = {(i, 10) for i in range(gs) if i not in [9, 10]} | {
        (10, j) for j in range(gs) if j not in [9, 10]
    }
    return (
        obs,
        [np.array([5, 5]), np.array([5, 15]), np.array([15, 5]), np.array([15, 15])],
        "bottleneck_warehouse",
    )


def create_dense_obstacle_warehouse(gs=20):
    np.random.seed(42)
    obs = {
        (np.random.randint(1, gs - 1), np.random.randint(1, gs - 1))
        for _ in range(int(gs * gs * 0.15))
    }
    return (
        obs,
        [np.array([3, 3]), np.array([16, 16]), np.array([3, 16]), np.array([16, 3])],
        "dense_obstacle",
    )


def create_hf_warehouse1(gs=20):
    obs = {
        (i, j)
        for i in range(gs)
        for j in range(gs)
        if not ((4 <= i <= 6) or (13 <= i <= 15) or (4 <= j <= 6) or (13 <= j <= 15))
        and (i + j) % 3 == 0
    }
    return (
        obs,
        [np.array([5, 5]), np.array([5, 14]), np.array([14, 5]), np.array([14, 14])],
        "hf_intersection",
    )


def create_hf_warehouse2(gs=20):
    obs = {
        (i, j)
        for i in range(2, gs - 2, 3)
        for j in range(gs)
        if j not in [0, 1, gs - 2, gs - 1, 9, 10]
    }
    return (
        obs,
        [
            np.array([1, 10]),
            np.array([gs - 2, 10]),
            np.array([10, 1]),
            np.array([10, gs - 2]),
        ],
        "hf_aisle",
    )


def create_hf_warehouse3(gs=20):
    obs = set()
    for cx, cy in [(5, 5), (5, 15), (15, 5), (15, 15)]:
        for dx in range(-2, 3):
            for dy in range(-2, 3):
                if abs(dx) + abs(dy) == 2:
                    obs.add((cx + dx, cy + dy))
    return (
        obs,
        [
            np.array([10, 10]),
            np.array([5, 10]),
            np.array([15, 10]),
            np.array([10, 5]),
            np.array([10, 15]),
        ],
        "hf_clusters",
    )


class TemporalCongestionPredictor(nn.Module):
    def __init__(self, grid_size=20, hidden_dim=64):
        super().__init__()
        self.conv1 = nn.Conv2d(3, hidden_dim, 3, padding=1)
        self.conv2 = nn.Conv2d(hidden_dim, hidden_dim, 3, padding=1)
        self.conv3 = nn.Conv2d(hidden_dim, 1, 3, padding=1)
        self.relu = nn.ReLU()

    def forward(self, x):
        x = self.relu(self.conv1(x))
        x = self.relu(self.conv2(x))
        return torch.sigmoid(self.conv3(x))


def generate_future_congestion_data(
    n_samples=300, obstacles=None, hotspots=None, horizon=10
):
    states, future_congestions = [], []
    for _ in range(n_samples):
        sim = WarehouseSimulator(obstacles=obstacles, hotspots=hotspots)
        active_tasks = np.where(sim.task_active)[0]
        sim.assign_tasks(
            [(i, active_tasks[i % len(active_tasks)]) for i in range(sim.n_agents)]
        )
        state = sim.get_state()
        future_cong = np.zeros((sim.grid_size, sim.grid_size))
        for t in range(horizon):
            sim.step()
            agent_grid = np.zeros((sim.grid_size, sim.grid_size))
            for pos in sim.agent_positions:
                agent_grid[pos[0], pos[1]] += 1
            future_cong += agent_grid * (0.9**t)
        future_cong /= future_cong.max() + 1e-6
        states.append(state)
        future_congestions.append(future_cong)
    return np.array(states), np.array(future_congestions)


def distance_based_assignment(agent_positions, task_positions, task_active):
    active_indices = np.where(task_active)[0]
    if len(active_indices) == 0:
        return []
    cost_matrix = np.array(
        [
            [np.sum(np.abs(ap - task_positions[ti])) for ti in active_indices]
            for ap in agent_positions
        ]
    )
    row_ind, col_ind = greedy_assignment(cost_matrix)
    return [(row_ind[i], active_indices[col_ind[i]]) for i in range(len(row_ind))]


def congestion_aware_assignment(
    agent_positions, task_positions, task_active, congestion_map, sim, weight=0.5
):
    active_indices = np.where(task_active)[0]
    if len(active_indices) == 0:
        return []
    cost_matrix = np.zeros((len(agent_positions), len(active_indices)))
    for i, ap in enumerate(agent_positions):
        for j, ti in enumerate(active_indices):
            path = sim._get_path_astar(ap, task_positions[ti])
            dist = len(path)
            path_cong = sum(congestion_map[p[0], p[1]] for p in path)
            cost_matrix[i, j] = dist + weight * path_cong
    row_ind, col_ind = greedy_assignment(cost_matrix)
    return [(row_ind[i], active_indices[col_ind[i]]) for i in range(len(row_ind))]


def train_predictor(
    model, train_s, train_c, val_s, val_c, epochs=50, batch_size=32, lr=0.001
):
    model = model.to(device)
    optimizer = optim.Adam(model.parameters(), lr=lr)
    criterion = nn.MSELoss()
    train_s_t = torch.FloatTensor(train_s).to(device)
    train_c_t = torch.FloatTensor(train_c).unsqueeze(1).to(device)
    val_s_t = torch.FloatTensor(val_s).to(device)
    val_c_t = torch.FloatTensor(val_c).unsqueeze(1).to(device)
    train_losses, val_losses = [], []
    for epoch in range(epochs):
        model.train()
        perm = torch.randperm(len(train_s))
        epoch_loss = 0
        for i in range(0, len(train_s), batch_size):
            idx = perm[i : i + batch_size]
            optimizer.zero_grad()
            loss = criterion(model(train_s_t[idx]), train_c_t[idx])
            loss.backward()
            optimizer.step()
            epoch_loss += loss.item()
        train_losses.append(epoch_loss / (len(train_s) // batch_size + 1))
        model.eval()
        with torch.no_grad():
            val_loss = criterion(model(val_s_t), val_c_t).item()
        val_losses.append(val_loss)
        if epoch % 10 == 0:
            print(f"Epoch {epoch}: validation_loss = {val_loss:.4f}")
    return model, train_losses, val_losses


def evaluate_method(method, model, sim_params, n_episodes=3, max_steps=80):
    throughputs, congestions = [], []
    for _ in range(n_episodes):
        sim = WarehouseSimulator(**sim_params)
        for _ in range(max_steps):
            state = sim.get_state()
            unassigned = [
                i
                for i in range(sim.n_agents)
                if sim.agent_targets[i] < 0 or not sim.task_active[sim.agent_targets[i]]
            ]
            if unassigned and np.any(sim.task_active):
                if method == "distance":
                    assignment = distance_based_assignment(
                        sim.agent_positions[unassigned],
                        sim.task_positions,
                        sim.task_active,
                    )
                else:
                    state_t = torch.FloatTensor(state).unsqueeze(0).to(device)
                    with torch.no_grad():
                        cong_pred = model(state_t).squeeze().cpu().numpy()
                    assignment = congestion_aware_assignment(
                        sim.agent_positions[unassigned],
                        sim.task_positions,
                        sim.task_active,
                        cong_pred,
                        sim,
                    )
                sim.assign_tasks([(unassigned[a], t) for a, t in assignment])
            sim.step()
        throughputs.append(sim.tasks_completed)
        congestions.append(sim.congestion_events)
    return np.mean(throughputs), np.mean(congestions)


